// build.gradle
dependencies {
    implementation 'com.squareup.okhttp3:okhttp:4.9.1'
    implementation 'com.squareup.retrofit2:retrofit:2.9.0'
    implementation 'com.squareup.retrofit2:converter-gson:2.9.0'
}

// NetworkModule.kt
object NetworkModule {
    private const val BASE_URL_DEV = "https://dev.api.example.com/"
    private const val BASE_URL_STAGING = "https://staging.api.example.com/"
    private const val BASE_URL_PROD = "https://api.example.com/"

    private fun getBaseUrl(): String {
        return when (BuildConfig.BUILD_TYPE) {
            "debug" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            else -> BASE_URL_PROD
        }
    }

    private val okHttpClient: OkHttpClient by lazy {
        OkHttpClient.Builder()
            .addInterceptor { chain ->
                val request = chain.request().newBuilder()
                    .addHeader("Authorization", "Bearer YOUR_AUTH_TOKEN")
                    .build()
                chain.proceed(request)
            }
            .build()
    }

    val retrofit: Retrofit by lazy {
        Retrofit.Builder()
            .baseUrl(getBaseUrl())
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
}

